class KernelMaxPooling1dCustom {
public:
    __aicore__ inline KernelMaxPooling1dCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalSeq,
                                uint32_t lengthIn,
                                uint32_t lengthOut,
                                uint32_t pad,
                                uint32_t ksize,
                                uint32_t stride)
    {
        totalSeq_ = totalSeq;
        lengthIn_ = lengthIn;
        lengthOut_ = lengthOut;
        pad_ = pad;
        ksize_ = ksize;
        stride_ = stride;

        xGm_.SetGlobalBuffer((__gm__ float*)x, static_cast<uint64_t>(totalSeq_) * lengthIn_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, static_cast<uint64_t>(totalSeq_) * lengthOut_);

        // Buffers:
        // inQueueX_: lengthIn
        // padQueue_: lengthIn + 2*pad
        // tmpQueue_: lengthOut
        // outQueueY_: lengthOut
        uint32_t padLen = lengthIn_ + 2u * pad_;
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, lengthIn_ * sizeof(float));
        pipe_.InitBuffer(padQueue_, 1, padLen * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, lengthOut_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, lengthOut_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalSeq_ == 0 || lengthOut_ == 0 || ksize_ == 0) {
            return;
        }

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        for (uint32_t seq = blockIdx; seq < totalSeq_; seq += blockNum) {
            const uint64_t xBase = static_cast<uint64_t>(seq) * lengthIn_;
            const uint64_t yBase = static_cast<uint64_t>(seq) * lengthOut_;

            // Load input sequence
            CopyIn(xBase, lengthIn_);

            // Create padded buffer and compute max pooling (stride currently supported: 1)
            Compute();

            // Store
            CopyOut(yBase, lengthOut_);
        }
    }

private:
    __aicore__ inline void CopyIn(uint64_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[gmOffset], len);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void Compute()
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> padLocal = padQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

        const uint32_t padLen = lengthIn_ + 2u * pad_;

        // padLocal = -INF
        // Fill zeros then min with -inf constant to get -inf everywhere
        AscendC::Muls(padLocal, padLocal, 0.0f, padLen);
        AscendC::Mins(padLocal, padLocal, -3.4028234e38f, padLen);

        // Copy x into padLocal starting at offset pad_
        AscendC::DataCopy(padLocal[pad_], xLocal, lengthIn_);

        if (stride_ == 1u) {
            // yLocal = max_{i in [0, ksize-1]} padLocal[i : i+lengthOut_]
            // Initialize with first window
            AscendC::DataCopy(yLocal, padLocal[0], lengthOut_);
            for (uint32_t k = 1; k < ksize_; ++k) {
                AscendC::DataCopy(tmpLocal, padLocal[k], lengthOut_);
                AscendC::Max(yLocal, yLocal, tmpLocal, lengthOut_);
            }
        } else {
            // General stride: compute by gathering for each shift into tmpLocal2 and taking max across shifts
            // Implementation: For each shift k in [0, ksize-1], gather elements padLocal[k + i*stride_] into tmpLocal,
            // then yLocal = max(yLocal, tmpLocal)
            // Initialize yLocal with first shift
            for (uint32_t i = 0; i < lengthOut_; ++i) {
                // Note: direct element access on LocalTensor via [] returns a slice; use DataCopy of 1 element
                // Build tmpLocal progressively
                // We will fill tmpLocal with padLocal[k + i*stride_], starting with k=0
                // First fill tmpLocal with padLocal[i*stride_]
                AscendC::DataCopy(tmpLocal[i], padLocal[i * stride_], 1);
            }
            // Accumulate maxima for remaining shifts
            for (uint32_t k = 1; k < ksize_; ++k) {
                // Load into xLocal buffer temporarily as tmpLocal2 by reusing xLocal (safe after use)
                for (uint32_t i = 0; i < lengthOut_; ++i) {
                    AscendC::DataCopy(xLocal[i], padLocal[k + i * stride_], 1);
                }
                AscendC::Max(tmpLocal, tmpLocal, xLocal, lengthOut_);
            }
            // Move tmpLocal to yLocal
            AscendC::DataCopy(yLocal, tmpLocal, lengthOut_);
        }

        outQueueY_.EnQue<float>(yLocal);
        tmpQueue_.FreeTensor(tmpLocal);
        padQueue_.FreeTensor(padLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint64_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> padQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalSeq_{0};
    uint32_t lengthIn_{0};
    uint32_t lengthOut_{0};
    uint32_t pad_{0};
    uint32_t ksize_{1};
    uint32_t stride_{1};
};

